<?php
$pageTitle='Push Notifications';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('push_notifications');
$pdo=getDB();$users=$pdo->query('SELECT id,email,role FROM '.table('users').' ORDER BY email LIMIT 300')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'queue');
    if($action==='queue'){createPushNotification($pdo,(int)($_POST['user_id']??0)?:null,trim((string)$_POST['role_slug']),trim((string)$_POST['title']),trim((string)$_POST['body']),trim((string)$_POST['target_url']),trim((string)$_POST['priority']));flash('success','Push notification queued.');}
    elseif($action==='deliver'){$result=simulatePushDelivery($pdo,(int)$_POST['id']);flash('success','Push delivery simulated: '.$result['delivered'].' delivered.');}
    elseif($action==='subscribe'){$number=nextScopedDocumentNumber($pdo,'push_subscription','PUSHSUB',operationalScope($pdo));$pdo->prepare('INSERT INTO '.table('push_notification_subscriptions').' (subscription_number,user_id,device_id,endpoint_url,p256dh_key,auth_key,platform,status,last_seen_at) VALUES (?,?,?,?,?,?,?,"active",NOW())')->execute([$number,(int)($_POST['user_id']??0)?:null,trim((string)$_POST['device_id']),trim((string)$_POST['endpoint_url']),trim((string)$_POST['p256dh_key']),trim((string)$_POST['auth_key']),trim((string)$_POST['platform'])]);flash('success','Push subscription added.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'push-notifications']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/push-notifications.php');
}
$queue=$pdo->query('SELECT q.*,u.email FROM '.table('push_notification_queue').' q LEFT JOIN '.table('users').' u ON u.id=q.user_id ORDER BY FIELD(q.status,"queued","pending_subscription","sent"),q.created_at DESC LIMIT 150')->fetchAll();
$subs=$pdo->query('SELECT s.*,u.email FROM '.table('push_notification_subscriptions').' s LEFT JOIN '.table('users').' u ON u.id=s.user_id ORDER BY s.created_at DESC LIMIT 100')->fetchAll();
$logs=$pdo->query('SELECT l.*,q.queue_number,s.subscription_number FROM '.table('push_notification_logs').' l LEFT JOIN '.table('push_notification_queue').' q ON q.id=l.push_notification_queue_id LEFT JOIN '.table('push_notification_subscriptions').' s ON s.id=l.push_notification_subscription_id ORDER BY l.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">PWA Notification Center</div><h2 class="h4 mb-1">Push Notifications</h2><p class="text-secondary mb-0">Manage push subscription foundation, notification queue and simulated delivery logs.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="queue"><h2 class="h5 mb-3">Queue Push</h2><select class="form-select mb-2" name="user_id"><option value="">Role / all users</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="role_slug" placeholder="admin / technician / customer"><input class="form-control mb-2" name="title" placeholder="Title"><textarea class="form-control mb-2" name="body" rows="3"></textarea><input class="form-control mb-2" name="target_url" placeholder="/mobile/index.php"><select class="form-select mb-3" name="priority"><option>low</option><option selected>normal</option><option>high</option><option>critical</option></select><button class="btn btn-brand w-100">Queue</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="subscribe"><h2 class="h5 mb-3">Manual Subscription</h2><select class="form-select mb-2" name="user_id"><option value="">No user</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="device_id" placeholder="device-id"><input class="form-control mb-2" name="platform" value="web"><textarea class="form-control mb-2" name="endpoint_url" rows="2" placeholder="endpoint"></textarea><input class="form-control mb-2" name="p256dh_key" placeholder="p256dh"><input class="form-control mb-3" name="auth_key" placeholder="auth"><button class="btn btn-outline-primary w-100">Add Subscription</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Queue</h2><table class="table"><thead><tr><th>Push</th><th>Recipient</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($queue as $q): ?><tr><td><strong><?php echo esc($q['queue_number']); ?></strong><div class="small text-secondary"><?php echo esc($q['title'].' · '.$q['body']); ?></div></td><td><?php echo esc($q['email']?:$q['role_slug']?:'All'); ?></td><td><span class="badge bg-<?php echo esc(statusTone($q['status'])); ?>"><?php echo esc($q['status']); ?></span></td><td><form method="post"><input type="hidden" name="action" value="deliver"><input type="hidden" name="id" value="<?php echo (int)$q['id']; ?>"><button class="btn btn-sm btn-outline-primary">Simulate</button></form></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Subscriptions</h2><table class="table"><tbody><?php foreach($subs as $s): ?><tr><td><strong><?php echo esc($s['subscription_number']); ?></strong><div class="small text-secondary"><?php echo esc(($s['email']?:'Guest').' · '.$s['platform'].' · '.$s['device_id']); ?></div></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Delivery Logs</h2><table class="table"><tbody><?php foreach($logs as $l): ?><tr><td><strong><?php echo esc($l['queue_number']); ?></strong><div class="small text-secondary"><?php echo esc($l['subscription_number'].' · '.$l['response_message']); ?></div></td><td><?php echo esc($l['delivery_status']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>